.darma-loader-cssloaders-github-36 {
  display: inline-block;
  width: 41px;
  height: 41px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--loader-color, #ef4444), var(--loader-secondary-color, #fecaca));
  animation: darma-loader-cssloaders-github-36-squareFlip 0.85s cubic-bezier(.55,.08,.38,.97) infinite;
}
